   267|export async function updateRequestStatus(
   268|  requestId: string,
   269|  status: EquipmentRequest['status'],
   270|  currentUid: string
   271|): Promise<void> {
   272|  const db = getFirebaseDb();
   273|  console.log('[Firestore] Updating request status:', requestId, '->', status);
   274|
   275|  const snap = await getDoc(doc(db, 'equipmentRequests', requestId));
   276|  if (!snap.exists()) throw new Error('Request not found');
   277|
   278|  const request = snap.data();
   279|  const isProvider = request.providerUid === currentUid;
   280|  const isCustomer = request.customerUid === currentUid;
   281|
   282|  const validTransitions: Record<string, { allowed: string[]; who: 'provider' | 'customer' | 'both' }> = {
   283|    pending: { allowed: ['accepted', 'rejected', 'cancelled'], who: 'both' },
   284|    accepted: { allowed: ['in_progress', 'cancelled'], who: 'both' },
   285|    in_progress: { allowed: ['completed'], who: 'provider' },
   286|  };
   287|
   288|  const current = request.status as string;
   289|  const rule = validTransitions[current];
   290|
   291|  if (!rule || !rule.allowed.includes(status)) {
   292|    throw new Error(`Invalid status transition: ${current} -> ${status}`);
   293|  }
   294|
   295|  if (rule.who === 'provider' && !isProvider) {
   296|    throw new Error('Only the provider can perform this action');
   297|  }
   298|
   299|  if (status === 'cancelled' && !isCustomer && !isProvider) {
   300|    throw new Error('Only participants can cancel');
   301|  }
   302|
   303|  const updates: Record<string, unknown> = {
   304|    status,
   305|    updatedAt: serverTimestamp(),
   306|  };
   307|
   308|  if (status === 'accepted') {
   309|    updates.allowChat = true;
   310|  }
   311|
   312|  if (status === 'completed' || status === 'rejected' || status === 'cancelled') {
   313|    updates.allowChat = false;
   314|  }
   315|
   316|  await updateDoc(doc(db, 'equipmentRequests', requestId), updates);
   317|  console.log('[Firestore] Request status updated');
   318|}
